import{_ as o,o as t,c as r,au as i}from"./chunks/framework.Bpqx6pAq.js";const p=JSON.parse('{"title":"Location utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/utilities/utils.location.md","filePath":"api/map/utilities/utils.location.md"}'),a={name:"api/map/utilities/utils.location.md"};function d(s,e,c,l,n,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="location-utilities" tabindex="-1">Location utilities <a class="header-anchor" href="#location-utilities" aria-label="Permalink to &quot;Location utilities&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This module provides utility functions for parsing, formatting, and filtering geographic coordinates and geocoding results.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="parsecoordinates-str" tabindex="-1"><code>parseCoordinates(str)</code> <a class="header-anchor" href="#parsecoordinates-str" aria-label="Permalink to &quot;`parseCoordinates(str)`&quot;">​</a></h3><p>Parses a coordinate string in either decimal-degree (<code>DD</code>) or simple decimal comma-separated format.</p><ul><li><strong>Parameters:</strong><ul><li><code>str</code> <em>(string)</em>: The coordinate string to parse. Supported formats: <ul><li>DD: <code>48.85°N 2.35°E</code> or <code>2.35°E 48.85°N</code></li><li>Simple: <code>-73.5, 45.5</code> (longitude, latitude)</li></ul></li></ul></li><li><strong>Returns:</strong> <code>{ longitude, latitude }</code> or <code>undefined</code> if the string does not match any supported format.</li></ul><hr><h3 id="formatusercoordinates-lat-lon-format-options" tabindex="-1"><code>formatUserCoordinates(lat, lon, format, options)</code> <a class="header-anchor" href="#formatusercoordinates-lat-lon-format-options" aria-label="Permalink to &quot;`formatUserCoordinates(lat, lon, format, options)`&quot;">​</a></h3><p>Formats a latitude/longitude pair as a human-readable string.</p><ul><li><strong>Parameters:</strong><ul><li><code>lat</code> <em>(number)</em>: Latitude.</li><li><code>lon</code> <em>(number)</em>: Longitude.</li><li><code>format</code> <em>(string)</em>: A <a href="https://github.com/nerik/formatcoords" target="_blank" rel="noreferrer">formatcoords</a> format string, or <code>&#39;aeronautical&#39;</code> for ICAO aeronautical notation.</li><li><code>options</code> <em>(Object)</em>: Additional options passed to <code>formatcoords</code> (ignored in aeronautical mode).</li></ul></li><li><strong>Returns:</strong> <code>string</code> — The formatted coordinate string.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The aeronautical format produces strings like <code>4851N 00221E</code>, following ICAO conventions where latitude and longitude are expressed as <code>DDMMMN/S DDDMMME/W</code> with tenths of minutes.</p></div><hr><h3 id="formatforwardgeocodingresult-result" tabindex="-1"><code>formatForwardGeocodingResult(result)</code> <a class="header-anchor" href="#formatforwardgeocodingresult-result" aria-label="Permalink to &quot;`formatForwardGeocodingResult(result)`&quot;">​</a></h3><p>Extracts a human-readable address label from a forward geocoding result feature.</p><p>The function tries the following sources in order:</p><ol><li><code>properties.formattedAddress</code></li><li>Assembled from <code>streetNumber</code>, <code>streetName</code>, <code>city</code>, <code>zipcode</code></li><li>The property named in <code>result.geokoder.matchProp</code></li></ol><ul><li><strong>Parameters:</strong><ul><li><code>result</code> <em>(Object)</em>: A geocoding result GeoJSON feature with a <code>properties</code> object.</li></ul></li><li><strong>Returns:</strong> <code>string | undefined</code> — The label string, or <code>undefined</code> if the result is invalid.</li></ul><hr><h3 id="filtergeocoders-geocoders-project" tabindex="-1"><code>filterGeocoders(geocoders, project)</code> <a class="header-anchor" href="#filtergeocoders-geocoders-project" aria-label="Permalink to &quot;`filterGeocoders(geocoders, project)`&quot;">​</a></h3><p>Filters a list of geocoder IDs to only include those relevant to the given project&#39;s layers.</p><p>When a geocoder source starts with <code>kano:</code>, the function checks whether the corresponding service is used by one of the project&#39;s layers (either as <code>service</code> or <code>probeService</code>). Non-<code>kano:</code> geocoders are always included.</p><ul><li><strong>Parameters:</strong><ul><li><code>geocoders</code> <em>(Array)</em>: Array of geocoder descriptors (strings or <code>{ value, label }</code> objects).</li><li><code>project</code> <em>(Object | null)</em>: The current project object containing a <code>layers</code> array, or <code>null</code>/<code>undefined</code> to skip filtering.</li></ul></li><li><strong>Returns:</strong> <code>Array</code> — The filtered geocoder array.</li></ul>',23)])])}const h=o(a,[["render",d]]);export{p as __pageData,h as default};
